export interface Node {
  id: string;
  path: string;
  type: 'file' | 'directory';
  lastModified: number;
  metadata?: Record<string, unknown>;
}

export interface Edge {
  id: string;
  source: string;
  target: string;
  type: string;
  metadata?: Record<string, unknown>;
}

export interface IndexState {
  lastIndexedRef: string;
  nodes: Map<string, Node>;
  edges: Map<string, Edge>;
  indexedAt: number;
}

export interface IncrementalIndexOptions {
  cwd?: string;
  includePatterns?: RegExp[];
  excludePatterns?: RegExp[];
  onNodeAdded?: (node: Node) => void;
  onNodeUpdated?: (node: Node) => void;
  onNodeRemoved?: (nodeId: string) => void;
  onEdgeAdded?: (edge: Edge) => void;
  onEdgeRemoved?: (edgeId: string) => void;
}

export interface IndexUpdateResult {
  added: Node[];
  updated: Node[];
  removed: string[];
  edgesAdded: Edge[];
  edgesRemoved: string[];
  newRef: string;
}

class Database {
  private nodes: Map<string, Node> = new Map();
  private edges: Map<string, Edge> = new Map();

  getNode(id: string): Node | undefined {
    return this.nodes.get(id);
  }

  setNode(node: Node): void {
    this.nodes.set(node.id, node);
  }

  deleteNode(id: string): boolean {
    return this.nodes.delete(id);
  }

  getAllNodes(): Node[] {
    return Array.from(this.nodes.values());
  }

  getEdge(id: string): Edge | undefined {
    return this.edges.get(id);
  }

  setEdge(edge: Edge): void {
    this.edges.set(edge.id, edge);
  }

  deleteEdge(id: string): boolean {
    return this.edges.delete(id);
  }

  getEdgesForNode(nodeId: string): Edge[] {
    return Array.from(this.edges.values()).filter(
      e => e.source === nodeId || e.target === nodeId
    );
  }

  clear(): void {
    this.nodes.clear();
    this.edges.clear();
  }
}

function generateNodeId(path: string): string {
  return `node:${path}`;
}

function generateEdgeId(source: string, target: string, type: string): string {
  return `edge:${source}:${target}:${type}`;
}

function createNodeFromPath(filePath: string): Node {
  return {
    id: generateNodeId(filePath),
    path: filePath,
    type: 'file',
    lastModified: Date.now()
  };
}

function detectEdges(node: Node, allNodes: Node[]): Edge[] {
  const edges: Edge[] = [];
  const pathParts = node.path.split('/');

  for (let i = 1; i < pathParts.length; i++) {
    const parentPath = pathParts.slice(0, i).join('/');
    const parentId = generateNodeId(parentPath);

    if (allNodes.some(n => n.id === parentId) || i < pathParts.length - 1) {
      edges.push({
        id: generateEdgeId(parentId, node.id, 'contains'),
        source: parentId,
        target: node.id,
        type: 'contains'
      });
    }
  }

  return edges;
}

export class IncrementalIndexer {
  private db: Database;
  private options: IncrementalIndexOptions;
  private currentRef: string | null = null;

  constructor(options: IncrementalIndexOptions = {}) {
    this.db = new Database();
    this.options = options;
  }

  async detectChanges(): Promise<{
    diff: DiffResult;
    untracked: string[];
  }> {
    const cwd = this.options.cwd || process.cwd();

    const diff = getChangedFiles({ cwd });
    const untracked = getUntrackedFiles(cwd);

    return { diff, untracked };
  }

  async updateIndex(): Promise<IndexUpdateResult> {
    const { diff, untracked } = await this.detectChanges();

    const relevantFiles = filterRelevantFiles(
      diff.files,
      this.options.includePatterns,
      this.options.excludePatterns
    );

    const result: IndexUpdateResult = {
      added: [],
      updated: [],
      removed: [],
      edgesAdded: [],
      edgesRemoved: [],
      newRef: diff.toRef
    };

    for (const change of relevantFiles) {
      await this.processChange(change, result);
    }

    for (const untrackedPath of untracked) {
      if (this.shouldIncludeFile(untrackedPath)) {
        await this.processUntracked(untrackedPath, result);
      }
    }

    this.currentRef = diff.toRef;

    return result;
  }

  private shouldIncludeFile(filePath: string): boolean {
    const { includePatterns, excludePatterns } = this.options;

    if (excludePatterns?.some(p => p.test(filePath))) {
      return false;
    }

    if (!includePatterns || includePatterns.length === 0) {
      return true;
    }

    return includePatterns.some(p => p.test(filePath));
  }

  private async processChange(
    change: FileChange,
    result: IndexUpdateResult
  ): Promise<void> {
    const nodeId = generateNodeId(change.path);

    switch (change.status) {
      case 'added':
        await this.handleAdded(change.path, result);
        break;

      case 'modified':
        await this.handleModified(change.path, result);
        break;

      case 'deleted':
        await this.handleDeleted(change.path, result);
        break;

      case 'renamed':
        if (change.oldPath) {
          await this.handleRenamed(change.oldPath, change.path, result);
        }
        break;
    }
  }

  private async handleAdded(
    filePath: string,
    result: IndexUpdateResult
  ): Promise<void> {
    const node = createNodeFromPath(filePath);
    const existing = this.db.getNode(node.id);

    this.db.setNode(node);

    if (existing) {
      result.updated.push(node);
      this.options.onNodeUpdated?.(node);
    } else {
      result.added.push(node);
      this.options.onNodeAdded?.(node);
    }

    const allNodes = this.db.getAllNodes();
    const edges = detectEdges(node, allNodes);

    for (const edge of edges) {
      this.db.setEdge(edge);
      result.edgesAdded.push(edge);
      this.options.onEdgeAdded?.(edge);
    }
  }

  private async handleModified(
    filePath: string,
    result: IndexUpdateResult
  ): Promise<void> {
    const nodeId = generateNodeId(filePath);
    const existing = this.db.getNode(nodeId);

    const node: Node = {
      id: nodeId,
      path: filePath,
      type: 'file',
      lastModified: Date.now(),
      metadata: existing?.metadata
    };

    this.db.setNode(node);
    result.updated.push(node);
    this.options.onNodeUpdated?.(node);
  }

  private async handleDeleted(
    filePath: string,
    result: IndexUpdateResult
  ): Promise<void> {
    const nodeId = generateNodeId(filePath);

    const edges = this.db.getEdgesForNode(nodeId);
    for (const edge of edges) {
      this.db.deleteEdge(edge.id);
      result.edgesRemoved.push(edge.id);
      this.options.onEdgeRemoved?.(edge.id);
    }

    this.db.deleteNode(nodeId);
    result.removed.push(nodeId);
    this.options.onNodeRemoved?.(nodeId);
  }

  private async handleRenamed(
    oldPath: string,
    newPath: string,
    result: IndexUpdateResult
  ): Promise<void> {
    const oldId = generateNodeId(oldPath);
    const newId = generateNodeId(newPath);

    const existing = this.db.getNode(oldId);

    const edges = this.db.getEdgesForNode(oldId);
    for (const edge of edges) {
      this.db.deleteEdge(edge.id);
      result.edgesRemoved.push(edge.id);
      this.options.onEdgeRemoved?.(edge.id);
    }

    this.db.deleteNode(oldId);
    result.removed.push(oldId);
    this.options.onNodeRemoved?.(oldId);

    const newNode: Node = {
      id: newId,
      path: newPath,
      type: 'file',
      lastModified: Date.now(),
      metadata: existing?.metadata
    };

    this.db.setNode(newNode);
    result.added.push(newNode);
    this.options.onNodeAdded?.(newNode);

    const allNodes = this.db.getAllNodes();
    const newEdges = detectEdges(newNode, allNodes);

    for (const edge of newEdges) {
      this.db.setEdge(edge);
      result.edgesAdded.push(edge);
      this.options.onEdgeAdded?.(edge);
    }
  }

  private async processUntracked(
    filePath: string,
    result: IndexUpdateResult
  ): Promise<void> {
    await this.handleAdded(filePath, result);
  }

  saveIndexRef(): void {
    if (this.currentRef) {
      saveIndexRef(this.currentRef, this.options.cwd);
    }
  }

  getNode(id: string): Node | undefined {
    return this.db.getNode(id);
  }

  getAllNodes(): Node[] {
    return this.db.getAllNodes();
  }

  getEdgesForNode(nodeId: string): Edge[] {
    return this.db.getEdgesForNode(nodeId);
  }

  clear(): void {
    this.db.clear();
    this.currentRef = null;
  }
}

export async function runIncrementalIndex(
  options: IncrementalIndexOptions = {}
): Promise<IndexUpdateResult> {
  const indexer = new IncrementalIndexer(options);
  const result = await indexer.updateIndex();
  indexer.saveIndexRef();
  return result;
}
